import {
  createContext,
  useContext,
  useEffect,
  useMemo,
  useState,
} from 'react';

// ==========================================
// 1. KHỞI TẠO CONTEXT
// ==========================================
export const CartContext = createContext(null);

// ==========================================
// 2. BỘ CUNG CẤP DỮ LIỆU (PROVIDER)
// ==========================================
export const CartProvider = ({ children }) => {
  const [cart, setCart] = useState([]);
  const [loading, setLoading] = useState(true);

  // Tải giỏ hàng từ localStorage lên khi vừa load trang
  useEffect(() => {
    try {
      const savedCart = localStorage.getItem('cart');
      if (savedCart) {
        setCart(JSON.parse(savedCart));
      }
    } catch (error) {
      console.error('Lỗi đọc giỏ hàng từ localStorage:', error);
      localStorage.removeItem('cart');
    } finally {
      setLoading(false);
    }
  }, []);

  // Hàm cốt lõi: Ghi đè trực tiếp State + LocalStorage cùng 1 lúc để triệt tiêu lag số
  const saveCartState = (newCart) => {
    setCart(newCart);
    localStorage.setItem('cart', JSON.stringify(newCart));
    // Tạo sự kiện toàn cục để ép các thanh Sidebar, Navbar cập nhật số tức thì
    window.dispatchEvent(new Event('storage'));
  };

  // THÊM VÀO GIỎ HÀNG
  const addToCart = (product) => {
    if (!product || !product.id) {
      console.error('Sản phẩm không hợp lệ');
      return;
    }

    const existingProduct = cart.find((item) => item.id === product.id);
    let updatedCart;

    if (existingProduct) {
      updatedCart = cart.map((item) =>
        item.id === product.id
          ? { ...item, quantity: item.quantity + 1 }
          : item
      );
    } else {
      updatedCart = [...cart, { ...product, quantity: 1 }];
    }

    saveCartState(updatedCart);
  };

  // XÓA SẢN PHẨM KHỎI GIỎ
  const removeFromCart = (id) => {
    const updatedCart = cart.filter((item) => item.id !== id);
    saveCartState(updatedCart);
  };

  // CẬP NHẬT SỐ LƯỢNG (DÙNG CHO Ô NHẬP HOẶC THAY ĐỔI TRỰC TIẾP)
  const updateQuantity = (id, quantity) => {
    if (quantity <= 0) {
      removeFromCart(id);
      return;
    }

    const updatedCart = cart.map((item) =>
      item.id === id ? { ...item, quantity } : item
    );
    saveCartState(updatedCart);
  };

  // TĂNG SỐ LƯỢNG (+1)
  const increaseQuantity = (id) => {
    const updatedCart = cart.map((item) =>
      item.id === id ? { ...item, quantity: item.quantity + 1 } : item
    );
    saveCartState(updatedCart);
  };

  // GIẢM SỐ LƯỢNG (-1)
  const decreaseQuantity = (id) => {
    const updatedCart = cart
      .map((item) =>
        item.id === id ? { ...item, quantity: item.quantity - 1 } : item
      )
      .filter((item) => item.quantity > 0);
    saveCartState(updatedCart);
  };

  // XÓA SẠCH GIỎ HÀNG
  const clearCart = () => {
    saveCartState([]);
  };

  // TÍNH TỔNG TIỀN ĐƠN HÀNG
  const cartTotal = useMemo(() => {
    return cart.reduce(
      (total, item) => total + Number(item.price || 0) * item.quantity,
      0
    );
  }, [cart]);

  // TÍNH TỔNG SỐ LƯỢNG SẢN PHẨM TRONG GIỎ
  const cartCount = useMemo(() => {
    return cart.reduce((total, item) => total + item.quantity, 0);
  }, [cart]);

  // Đóng gói tất cả dữ liệu
  const value = useMemo(
    () => ({
      cart,
      loading,
      addToCart,
      removeFromCart,
      updateQuantity,
      increaseQuantity,
      decreaseQuantity,
      clearCart,
      cartTotal,
      cartCount,
    }),
    [cart, loading, cartTotal, cartCount]
  );

  return (
    <CartContext.Provider value={value}>
      {children}
    </CartContext.Provider>
  );
};

// ==========================================
// 3. CUSTOM HOOK (Dùng kiểu mới cực tiện)
// ==========================================
export const useCart = () => {
  const context = useContext(CartContext);
  if (!context) {
    throw new Error('useCart phải được sử dụng bên trong CartProvider');
  }
  return context;
};

// ==========================================
// 4. FIX LỖI IMPORT: Cho phép export cả Default lẫn Named
// ==========================================
export default CartContext;
